// PaymentManager.kt
package com.example.paymentapp.payment

import android.app.Activity
import android.content.Context
import com.android.billingclient.api.BillingClient
import com.android.billingclient.api.BillingClientStateListener
import com.android.billingclient.api.Purchase
import com.android.billingclient.api.PurchasesUpdatedListener
import com.android.billingclient.api.BillingResult
import com.android.billingclient.api.ProductDetails
import com.android.billingclient.api.QueryProductDetailsParams

class PaymentManager(
    private val context: Context,
    private val listener: PaymentListener
) : PurchasesUpdatedListener {

    private var billingClient: BillingClient? = null

    interface PaymentListener {
        fun onPurchaseSuccess(purchase: Purchase)
        fun onPurchaseError(errorCode: Int)
    }

    fun initBillingClient() {
        billingClient = BillingClient.newBuilder(context)
            .enablePendingPurchases()
            .setListener(this)
            .build()
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingServiceDisconnected() {}
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    // BillingClient connected
                }
            }
        })
    }

    fun queryAvailableProducts(productIds: List<String>, onResult: (List<ProductDetails>) -> Unit) {
        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productIds.map {
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId(it)
                    .setProductType(BillingClient.ProductType.INAPP)
                    .build()
            })
            .build()

        billingClient?.queryProductDetailsAsync(params) { _, productDetailsList ->
            onResult(productDetailsList)
        }
    }

    fun purchase(activity: Activity, productDetails: ProductDetails) {
        val billingFlowParams = com.android.billingclient.api.BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(
                listOf(
                    com.android.billingclient.api.BillingFlowParams.ProductDetailsParams.newBuilder()
                        .setProductDetails(productDetails)
                        .build()
                )
            )
            .build()
        billingClient?.launchBillingFlow(activity, billingFlowParams)
    }

    override fun onPurchasesUpdated(
        billingResult: BillingResult,
        purchases: MutableList<Purchase>?
    ) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
            purchases.forEach { listener.onPurchaseSuccess(it) }
        } else {
            listener.onPurchaseError(billingResult.responseCode)
        }
    }
}

// WalletRepository.kt
package com.example.paymentapp.wallet

import android.content.Context
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKeys

class WalletRepository(context: Context) {

    private val masterKeyAlias = MasterKeys.getOrCreate(MasterKeys.AES256_GCM_SPEC)
    private val sharedPreferences = EncryptedSharedPreferences.create(
        "wallet_encrypted_prefs",
        masterKeyAlias,
        context,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun getBalance(): Float {
        return sharedPreferences.getFloat("wallet_balance", 0f)
    }

    fun updateBalance(amount: Float) {
        sharedPreferences.edit().putFloat("wallet_balance", amount).apply()
    }
}

// PaymentViewModel.kt
package com.example.paymentapp.payment

import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import com.android.billingclient.api.Purchase
import com.android.billingclient.api.ProductDetails
import com.example.paymentapp.wallet.WalletRepository

class PaymentViewModel(private val walletRepository: WalletRepository) : ViewModel() {

    private val _productDetails = MutableLiveData<List<ProductDetails>>()
    val productDetails: LiveData<List<ProductDetails>> = _productDetails

    private val _purchaseSuccess = MutableLiveData<Purchase>()
    val purchaseSuccess: LiveData<Purchase> = _purchaseSuccess

    private val _errorCode = MutableLiveData<Int>()
    val errorCode: LiveData<Int> = _errorCode

    fun loadProducts(manager: PaymentManager, productIds: List<String>) {
        manager.queryAvailableProducts(productIds) {
            _productDetails.postValue(it)
        }
    }

    fun handlePurchaseSuccess(purchase: Purchase) {
        _purchaseSuccess.postValue(purchase)
        val currentBalance = walletRepository.getBalance()
        // Example credit to wallet
        walletRepository.updateBalance(currentBalance + 10f)
    }

    fun handlePurchaseError(code: Int) {
        _errorCode.postValue(code)
    }
}

// PaymentActivity.kt
package com.example.paymentapp.ui

import android.os.Bundle
import androidx.activity.viewModels
import androidx.appcompat.app.AppCompatActivity
import com.android.billingclient.api.Purchase
import com.example.paymentapp.payment.PaymentManager
import com.example.paymentapp.payment.PaymentViewModel
import com.example.paymentapp.wallet.WalletRepository

class PaymentActivity : AppCompatActivity(), PaymentManager.PaymentListener {

    private lateinit var paymentManager: PaymentManager
    private val paymentViewModel: PaymentViewModel by viewModels {
        PaymentViewModelFactory(WalletRepository(applicationContext))
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        paymentManager = PaymentManager(this, this)
        paymentManager.initBillingClient()
        paymentViewModel.loadProducts(paymentManager, listOf("example_product_id"))
    }

    override fun onPurchaseSuccess(purchase: Purchase) {
        paymentViewModel.handlePurchaseSuccess(purchase)
    }

    override fun onPurchaseError(errorCode: Int) {
        paymentViewModel.handlePurchaseError(errorCode)
    }
}

